import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"活体手套","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/活体手套.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/活体手套.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/活体手套.md"};function l(_,r,b,i,p,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"活体手套",tabindex:"-1"},[s("活体手套 "),e("a",{class:"header-anchor",href:"#活体手套","aria-label":'Permalink to "活体手套"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),o('<h1 id="活体手套-1" tabindex="-1">活体手套 <a class="header-anchor" href="#活体手套-1" aria-label="Permalink to &quot;活体手套&quot;">​</a></h1><p>活体手套<br> 本质：特异本质<br> 价格:D+500<br> 占据手套位<br> 这双共生体手套是活的，由薄薄的几丁质和肌腱构成，不断搏动着，该手套需要寄生后才可使用。宿主要一直戴着这双手套最少60分钟才能完成寄生，寄生期间肌腱缠绕，几丁质刺入宿主皮肤，在轻微的麻痹和痛苦中，与你的皮肤融为一体。<br> 寄生后的宿主手部看起来和之前别无二致，但仔细观察就会发现手部的毛孔变得非常细小，磨损所带来的角质层增生和毛发全部消失，指纹也模糊不清，这可以让一个如狼似虎的粗狂巨汉也拥有如同婴儿一般的手，在专业的侦察人员眼里变得相当的可疑。<br> 剥下手套需要一次DC为20的医疗检定。<br> 仅在第一次寄生时，宿主可以选择你以下专业提升1级，这是共生体手套为你提供的熟练度。<br> · 隐秘：手上功夫<br> · 器用：拆除<br> · 一种由你选择的手艺相关专业<br> · 一种由你选择的表达相关的乐器专业<br> 当你使用你所选择的手套熟练专业进行检定时，额外获得3DP增强加值。<br> 被活体手套寄生后，宿主可以以一个整轮动作，将自己的手腕以下的部分变形为任何21世纪现实存在的工具（而非原料），例如一把锤子，一根铁丝或是一柄夹子等等，长度最长为1米。手部变形出的工具虽然就像现实中那些普通的工具一样好用，但本质上依然是你的肢体，不能变出如电锯，射钉枪一类，需要额外动力驱动或消耗额外物质的工具，且进入高温，高压或类似的环境工作也会受损，因为本质上这和你把手放入这些空间没有区别，正常计算伤害即可。活体手套的手部变形视为D级的变形效果，其目是让你免受绝大多数情况下，因为无合适工具所需承担的减值。<br> 被活体手套所变形出的工具相当精细，但并不适用于战斗，若强行用于战斗，则武器伤害为你的天生武器伤害，在攻击检定上需要额外承受5点器械减值，且只能造成冲击伤害。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
